module.exports = /*#__PURE__*/JSON.parse('{"nav":{"home":"Home","schemes":"Schemes","fileComplaint":"File Complaint","trackComplaint":"Track Complaint","chatAssistant":"Chat Assistant","login":"Login","officerLogin":"Officer / Supervisor Login","logout":"Logout"},"landing":{"badge":"AI-Powered Civic Platform","headline":"Your Bridge to","headlineHighlight":"Delhi\'s Civic Services","subline":"Discover government schemes you qualify for. File and track civic complaints with full transparency, SLA guarantees, and AI assistance.","exploreSchemes":"Explore Schemes","fileComplaint":"File a Complaint","problemTitle":"The Civic Disconnect","problemSubtitle":"Delhi provides hundreds of services, but citizens often struggle to access them or hold agencies accountable.","missingSchemes":"Missing Schemes?","missingSchemesDesc":"Millions of rupees in welfare funds go unused because citizens don\'t know they qualify or find the application process confusing. Our AI engine matches your profile directly to active schemes.","lostComplaints":"Lost Complaints?","lostComplaintsDesc":"Civic complaints often fall into a black hole with no updates. We enforce strict SLAs (Service Level Agreements) that automatically escalate your issue if not resolved in time.","howItWorks":"How NyayaSetu Works","howItWorksSub":"Three simple steps to civic empowerment","step1":"Discover & Match","step1Desc":"Search through active government schemes or chat with our AI to get personalized recommendations based on your profile.","step2":"Act & Verify","step2Desc":"File complaints securely with OTP phone verification. Upload photo proof and let AI route it to the exact right department.","step3":"Track & Escalate","step3Desc":"Watch the SLA countdown in real-time. If the officer misses the deadline, the system automatically escalates it to their supervisor.","feat1Title":"AI-Driven Scheme Discovery","feat1Desc":"Stop guessing. Tell us your age, gender, occupation, and categories, and our rule-engine instantly matches you to schemes you actually qualify for, with plain-language explanations.","feat2Title":"Transparent Complaint Tracking","feat2Desc":"From submission to resolution, every status update is logged with proof. See exactly which officer is handling your case and how much time they have left.","feat3Title":"AI Chat Assistant","feat3Desc":"Speak directly to our bilingual AI assistant to get answers fast. Understand confusing municipal terminology, ask for links, or find out how things work.","statsListed":"Schemes Listed","statsDepts":"Civic Departments","statsTracking":"Real-time Tracking","statsAi":"AI-Powered","rolesTitle":"Built for Everyone","rolesSub":"A unified platform that connects citizens to the government apparatus.","roleCitizen":"Citizens","roleCitizenDesc":"Find schemes, file civic complaints instantly, and track progress with total transparency.","roleOfficer":"Officers","roleOfficerDesc":"Manage your assigned complaints efficiently, upload photo proofs, and hit SLA targets.","roleSupervisor":"Supervisors","roleSupervisorDesc":"Monitor city-wide complaint performance, reassign tasks, and resolve automatic escalations.","getStarted":"Get Started","ctaTitle":"Ready to make your voice heard?","ctaSub":"Join thousands of Delhi citizens building a better city.","ctaButton":"File a Complaint Now"},"about":{"title":"About NyayaSetu","subtitle":"A civic tech prototype aimed at bridging the gap between the citizens of Delhi and the municipal services they rely on.","problem":"The Problem","problemDesc1":"Delhi\'s municipal apparatus offers hundreds of schemes and services, but the system is often opaque. Citizens face two major challenges:","problemLi1":"Scheme Information Asymmetry: Welfare funds go unutilized because the people who need them most don\'t know they exist or don\'t know if they qualify.","problemLi2":"The Complaint Black Hole: Reporting a pothole or a broken streetlight often feels like shouting into the void. Without strict deadlines or transparency, complaints are easily ignored.","solution":"Our Solution","solutionDesc1":"NyayaSetu (\\"Bridge of Justice\\") tackles these issues directly through a dual-engine platform:","solution1Title":"1. AI Scheme Discovery","solution1Desc":"Instead of making citizens search for schemes, our rule-based engine matches citizen profiles (age, gender, category, occupation) against active schemes, telling them exactly why they qualify.","solution2Title":"2. SLA-Enforced Complaints","solution2Desc":"Every submitted complaint comes with a strict Service Level Agreement (SLA) countdown. If an officer doesn\'t resolve a water leak in 48 hours, the system automatically escalates it to their supervisor. No manual intervention needed.","tech":"Under The Hood","techDesc":"NyayaSetu is built on a modern, robust tech stack designed for speed and reliability:","disclaimer":"Disclaimer: NyayaSetu is a civic tech prototype developed to demonstrate how modern technology can improve municipal services. It is not an official portal of the Government of NCT of Delhi or the Municipal Corporation of Delhi (MCD)."},"footer":{"desc":"Your bridge to Delhi\'s civic services. Discover government schemes you qualify for, and file civic complaints with full transparency and accountability.","quickLinks":"Quick Links","aboutUs":"About Us","services":"Services","builtFor":"Built with ❤️ for the citizens of Delhi","disclaimer":"Disclaimer: NyayaSetu is a civic tech prototype. Not an official government portal."},"keyboard":{"title":"Hindi Keyboard","close":"Close keyboard","backspace":"Backspace","openHindi":"Open Hindi keyboard"},"chat":{"title":"NyayaSetu Assistant","subtitle":"AI-powered civic helpdesk","howCanIHelp":"How can I help you?","howCanIHelpSub":"Ask about government schemes, filing complaints, or municipal services","placeholder":"Type your message...","thinking":"Thinking...","networkError":"Network error. Please check your connection and try again.","greeting":"Hello! How can I help?","greetingSub":"Ask me about government schemes or civic issues","starter1":"What welfare schemes am I eligible for?","starter2":"How do I report a water leakage?","starter3":"How do I track my complaint?","starter4":"What is SLA and why does it matter?","errorGeneral":"Sorry, something went wrong. Please try again.","errorNetwork":"Network error. Please check your connection."},"schemes":{"title":"Government Schemes","subtitle":"Discover and apply for welfare schemes in Delhi","searchPlaceholder":"Search schemes...","btnDiscover":"Discover For Me","btnAll":"All Schemes","btnApply":"Apply Now","btnDetails":"View Details","minAge":"Min Age","years":"years","noSchemes":"No schemes found matching your criteria.","recommendTitle":"Get Personalized Recommendations","recommendSub":"Tell us about yourself to find schemes you qualify for.","ageGroup":"Age Group","gender":"Gender","occupation":"Occupation","socialCategory":"Social Category","hasDisability":"Do you have any disability?","yes":"Yes","no":"No","btnFind":"Find Schemes","finding":"Finding schemes...","selectOption":"Select an option","details":"Scheme Details","eligibility":"Eligibility Criteria","benefits":"Benefits","howToApply":"How to Apply","documents":"Required Documents","back":"Back to Schemes"},"complaint":{"fileTitle":"File a Complaint","fileSub":"Report a civic issue in Delhi. Please verify your phone number first.","step1":"Step 1: Phone Verification","step2":"Step 2: Complaint Details","phone":"Phone Number","phonePlaceholder":"Enter 10-digit number","btnSendOtp":"Send OTP","sending":"Sending...","otp":"One Time Password","otpPlaceholder":"Enter 6-digit OTP","btnVerify":"Verify OTP","verifying":"Verifying...","verified":"Phone Verified","name":"Full Name","description":"Describe the issue","descPlaceholder":"E.g., The streetlight outside house no 42 has been broken for 3 days.","pincode":"Pincode","image":"Proof Image","imageSub":"Capture or upload a photo of the issue","btnSubmit":"Submit Complaint","submitting":"Submitting...","success":"Complaint Submitted Successfully!","uidLabel":"Your Complaint ID is:","trackNow":"Track Complaint","trackTitle":"Track Complaint","trackSub":"Enter your Complaint ID (UID) to check its real-time status","uidPlaceholder":"e.g. NYC-2026...","btnTrack":"Track Status","tracking":"Tracking...","status":"Current Status","category":"Category","department":"Department","pincodeLabel":"Pincode","sla":"SLA Deadline","officer":"Assigned Officer","timeline":"Timeline","feedbackTitle":"Complaint Resolved","feedbackSub":"Are you satisfied with the resolution?","btnSatisfied":"Yes, I am satisfied","btnReopen":"No, reopen complaint","feedbackSubmitted":"Feedback submitted. Thank you!","notAssigned":"Not Assigned Yet","trackByPhone":"Track by Phone","trackByUid":"Track by Complaint ID","phoneTabDesc":"Enter your registered phone number to find all linked complaints.","sendOtpToPhone":"Send OTP to phone","phoneVerifiedFinding":"Phone verified. Finding your complaints...","complaintsLinked":"Complaints linked to your number","noComplaintsPhone":"No complaints found for this phone number.","yourComplaints":"Your Complaints","viewComplaint":"View Details"},"dashboard":{"welcome":"Welcome","officerPortal":"Officer Portal","supervisorPortal":"Supervisor Dashboard","total":"Total","assigned":"Assigned","active":"Active","resolved":"Resolved","overdue":"Overdue","escalated":"Escalated","slaCompliance":"SLA Compliance","avgResolution":"Avg Resolution","hours":"hours","queue":"Complaint Queue","viewDetails":"View Details","updateStatus":"Update Status","uploadProof":"Upload Resolution Proof","transferDesc":"Transfer to another department","btnUpdate":"Update","btnUpload":"Upload","btnTransfer":"Transfer","remark":"Officer Remark","noComplaints":"No complaints found.","officerPerformance":"Officer Performance","overdueQueue":"Overdue Complaints","escalate":"Escalate","reassign":"Reassign Officer","action":"Action"},"status":{"submitted":"Submitted","verified":"Verified","assigned":"Assigned","in_progress":"In Progress","resolved":"Resolved","closed":"Closed","escalated":"Escalated","reopened":"Reopened","transferred":"Transferred"},"categories":{"garbage_collection":"Garbage Collection","water_leakage":"Water Leakage","sewer_blockage":"Sewer Blockage","drain_overflow":"Drain Overflow","streetlight":"Streetlight Issue","pothole":"Pothole","illegal_dumping":"Illegal Dumping","mosquito_sanitation":"Mosquito/Sanitation","stray_animal":"Stray Animal","park_maintenance":"Park Maintenance","encroachment":"Encroachment"},"departments":{"dept_001":"Sanitation & Solid Waste","dept_002":"Water & Sewerage","dept_003":"Electrical & Street Lighting","dept_004":"Roads & Infrastructure","dept_005":"Parks & Environment","dept_006":"Animal Control","dept_007":"Anti-Encroachment"},"filters":{"all":"All Schemes","students":"Students","women":"Women","senior_citizens":"Senior Citizens","small_business":"Small Business","workers":"Workers","disability":"Disability","farmers":"Farmers"},"supervisor":{"heatmap":{"title":"Ward Complaint Heatmap","description":"Color intensity indicates complaint volume per ward.","legend":{"none":"0 complaints","low":"1–5","medium":"6–15","high":"16+"},"overdue":"Overdue"}}}');

